def extract_state(desc):
    # Try multiple patterns
    # Pattern 1: ", ST,"
    match = re.search(r', ([A-Z]{2}),', desc)
    if match:
        return match.group(1)

    # Pattern 2: ", ST location"
    match = re.search(r', ([A-Z]{2}) location', desc)
    if match:
        return match.group(1)

